// Normalizar e calcular hash de cada linha para detectar mudanças
const rows = $input.all();
const result = [];

for (const item of rows) {
  const row = item.json;

  // Pular linhas sem título
  if (!row['Titulo'] && !row['titulo'] && !row['TITULO']) continue;

  const titulo = String(row['Titulo'] || row['titulo'] || row['TITULO'] || '').trim();
  const idProcesso = String(row['ID_Processo'] || row['id_processo'] || row['Processo'] || '').trim() || null;
  const tipo = String(row['Tipo'] || row['tipo'] || 'servico').trim().toLowerCase();
  const secretaria = String(row['Secretaria'] || row['secretaria'] || 'SMPG').trim();
  const componente = String(row['Componente'] || row['componente'] || '').trim() || null;
  const valorUSD = parseFloat(String(row['Valor_USD'] || row['valor_usd'] || '0').replace(/[^0-9.]/g, '')) || null;
  const status = String(row['Status'] || row['status'] || 'planejado').trim().toLowerCase();
  const modalidade = String(row['Modalidade'] || row['modalidade'] || '').trim() || null;
  const lote = String(row['Lote'] || row['lote'] || '').trim() || null;
  const fidic = String(row['FIDIC'] || row['fidic'] || '').toLowerCase() === 'sim';
  const dataInicio = String(row['Data_Inicio'] || row['data_inicio_previsto'] || '').trim() || null;
  const notas = String(row['Notas'] || row['notas'] || '').trim() || null;

  // Mapear tipo para valores válidos do CHECK constraint
  const tipoMap = { 'obra': 'obra', 'consultoria': 'consultoria', 'bem': 'bem', 'servico': 'servico', 'fidic': 'fidic' };
  const tipoNorm = tipoMap[tipo] || 'servico';

  // Mapear secretaria para valores válidos
  const secMap = ['SMPG','SMS','SMAS','SMED','SMID','SMDET','PROCEMPA','DEMHAB','Outro'];
  const secretariaNorm = secMap.includes(secretaria) ? secretaria : 'Outro';

  // Mapear status para valores válidos
  const statusMap = ['planejado','preparacao','publicado','em_avaliacao','adjudicado','contratado','em_execucao','concluido','cancelado'];
  const statusNorm = statusMap.includes(status) ? status : 'planejado';

  const record = {
    titulo,
    id_processo: idProcesso,
    tipo: tipoNorm,
    secretaria: secretariaNorm,
    componente,
    valor_usd: valorUSD,
    status: statusNorm,
    modalidade,
    lote,
    fidic_aplicavel: fidic,
    data_inicio_previsto: dataInicio,
    notas,
    financiador: 'BID'
  };

  // Gerar hash simples para comparação
  const hash = JSON.stringify(record);
  result.push({ json: { ...record, _hash: hash } });
}

return result;

// Agregar resultado e preparar log
const items = $input.all();
const inseridos = items.filter(i => i.json?.id).length;
const erros = items.filter(i => i.json?.error || i.json?.message).length;

return [{ json: {
  tabela_destino: 'aquisicoes',
  fonte: 'google_sheets_dpf',
  versao: new Date().toISOString().slice(0,10).replace(/-/g,''),
  registros_lidos: items.length,
  registros_inseridos: inseridos,
  registros_atualizados: 0,
  registros_erro: erros,
  status: erros === 0 ? 'ok' : 'parcial',
  executado_por: 'n8n_sync_sheets'
}}];
